const source = $json.body ?? $json;

const asList = (value) => {
  if (Array.isArray(value)) return value.map(String).map((item) => item.trim()).filter(Boolean);
  if (value === undefined || value === null || value === '') return [];
  return String(value)
    .split(/[\n,;]+/)
    .map((item) => item.trim())
    .filter(Boolean);
};

const firstNonEmpty = (...values) => values.find((value) => value !== undefined && value !== null && String(value).trim() !== '') ?? '';

return [
  {
    json: {
      received_at: new Date().toISOString(),
      job: {
        title: firstNonEmpty(source.job_title, source.job?.title),
        marketplace: firstNonEmpty(source.marketplace, source.job?.marketplace),
        category: firstNonEmpty(source.category, source.job?.category),
        must_have: asList(firstNonEmpty(source.must_have, source.job?.must_have)),
        nice_to_have: asList(firstNonEmpty(source.nice_to_have, source.job?.nice_to_have)),
      },
      candidate: {
        name: firstNonEmpty(source.candidate_name, source.candidate?.name),
        resume: firstNonEmpty(source.candidate_resume, source.candidate?.resume),
        salary_expectation: firstNonEmpty(source.salary_expectation, source.candidate?.salary_expectation),
        contact: firstNonEmpty(source.contact, source.candidate?.contact),
      },
      raw_input: source,
    },
  },
];

const data = $json;
const job = data.job;
const candidate = data.candidate;
const resume = String(candidate.resume || '').toLowerCase();
const normalize = (value) => String(value || '').toLowerCase();

const keywordHit = (keyword) => {
  const words = normalize(keyword)
    .replace(/[^a-zа-я0-9+/#.\s-]/gi, ' ')
    .split(/\s+/)
    .filter((word) => word.length > 2);
  if (!words.length) return false;
  return words.some((word) => resume.includes(word));
};

const mustHave = job.must_have || [];
const niceToHave = job.nice_to_have || [];
const matchedMust = mustHave.filter(keywordHit);
const missingMust = mustHave.filter((item) => !matchedMust.includes(item));
const matchedNice = niceToHave.filter(keywordHit);

const marketplace = normalize(job.marketplace);
const marketplaceTerms = [marketplace, 'wildberries', 'wb', 'ozon'].filter(Boolean);
const hasMarketplaceExperience = marketplaceTerms.some((term) => resume.includes(term));
const toolTerms = ['excel', 'google sheets', 'mpstats', 'marketguru', 'cabinet', 'кабинет', 'аналитик', 'аналитика', 'реклама', 'фулфилмент', 'seo', 'карточк'];
const matchedTools = toolTerms.filter((term) => resume.includes(term));

const mustScore = mustHave.length ? Math.round((matchedMust.length / mustHave.length) * 45) : 25;
const niceScore = niceToHave.length ? Math.round((matchedNice.length / niceToHave.length) * 15) : 5;
const marketplaceScore = hasMarketplaceExperience ? 20 : 0;
const toolsScore = Math.min(15, matchedTools.length * 3);
const salaryScore = candidate.salary_expectation ? 5 : 0;
const fitScore = Math.max(0, Math.min(100, mustScore + niceScore + marketplaceScore + toolsScore + salaryScore));

let verdict = 'needs_review';
if (fitScore >= 80 && missingMust.length <= 1) verdict = 'strong_match';
if (fitScore < 55 || missingMust.length >= Math.max(2, Math.ceil(mustHave.length / 2))) verdict = 'low_match';

const verdictText = {
  strong_match: 'Сильный кандидат: можно быстро передавать рекрутеру на следующий этап.',
  needs_review: 'Средний матч: стоит уточнить несколько деталей до интервью.',
  low_match: 'Слабое совпадение: не хватает ключевых требований под вакансию.',
}[verdict];

const strengths = [];
if (matchedMust.length) strengths.push(`Совпал must-have: ${matchedMust.join(', ')}`);
if (matchedNice.length) strengths.push(`Есть nice-to-have: ${matchedNice.join(', ')}`);
if (hasMarketplaceExperience) strengths.push(`Есть релевантный опыт с ${job.marketplace || 'маркетплейсами'}.`);
if (matchedTools.length) strengths.push(`В резюме найдены инструменты/темы: ${[...new Set(matchedTools)].slice(0, 6).join(', ')}.`);
if (!strengths.length) strengths.push('В резюме есть общий коммерческий опыт, но мало явных сигналов под маркетплейсы.');

const risks = [];
if (missingMust.length) risks.push(`Не подтверждены требования: ${missingMust.join(', ')}`);
if (!hasMarketplaceExperience) risks.push('Не найден явный опыт WB/Ozon в тексте резюме.');
if (!candidate.salary_expectation) risks.push('Не указаны зарплатные ожидания.');
if (!risks.length) risks.push('Критичных рисков на первичном скоринге не найдено.');

const followUpQuestions = [
  `С какими задачами на ${job.marketplace || 'маркетплейсах'} кандидат работал лично, а не через команду?`,
  'Какие метрики кандидат улучшал: выручка, ДРР, конверсия, остатки, рейтинг карточек?',
  'Какие инструменты аналитики и рекламы использовал в ежедневной работе?',
];
if (missingMust.length) followUpQuestions.unshift(`Попросить примеры по требованиям: ${missingMust.slice(0, 3).join(', ')}.`);

const recruiterSummary = `${candidate.name || 'Кандидат'} на позицию "${job.title || 'без названия'}": ${fitScore}/100. ${verdictText} Сильные стороны: ${strengths.join(' ')} Риски: ${risks.join(' ')}`;
const candidateMessage = `Привет, ${candidate.name || 'коллега'}! Меня заинтересовал твой опыт под вакансию "${job.title || 'в e-commerce'}" для ${job.marketplace || 'маркетплейсов'}. Хочу коротко уточнить пару деталей по задачам, инструментам и ожиданиям - удобно обсудить сегодня или завтра?`;

return [
  {
    json: {
      ...data,
      ai_result: {
        fit_score: fitScore,
        verdict,
        verdict_text: verdictText,
        strengths,
        risks,
        recruiter_summary: recruiterSummary,
        candidate_message: candidateMessage,
        follow_up_questions: followUpQuestions,
        matched_must_have: matchedMust,
        missing_must_have: missingMust,
        matched_nice_to_have: matchedNice,
      },
    },
  },
];

const data = $json;
const serializedInput = JSON.stringify(data.raw_input || {});
const serializedOutput = JSON.stringify(data.ai_result || {});
const estimatedInputTokens = Math.ceil(serializedInput.length / 4);
const estimatedOutputTokens = Math.ceil(serializedOutput.length / 4);
const estimatedTokens = estimatedInputTokens + estimatedOutputTokens;
const estimatedCostRub = Number(((estimatedTokens / 1000) * 0.18).toFixed(2));

return [
  {
    json: {
      timestamp: data.received_at,
      candidate_name: data.candidate.name,
      contact: data.candidate.contact,
      job_title: data.job.title,
      marketplace: data.job.marketplace,
      category: data.job.category,
      fit_score: data.ai_result.fit_score,
      verdict: data.ai_result.verdict,
      verdict_text: data.ai_result.verdict_text,
      strengths: data.ai_result.strengths.join('\n'),
      risks: data.ai_result.risks.join('\n'),
      recruiter_summary: data.ai_result.recruiter_summary,
      candidate_message: data.ai_result.candidate_message,
      follow_up_questions: data.ai_result.follow_up_questions.join('\n'),
      estimated_input_tokens: estimatedInputTokens,
      estimated_output_tokens: estimatedOutputTokens,
      estimated_tokens: estimatedTokens,
      estimated_cost_rub: estimatedCostRub,
      status: data.ai_result.verdict === 'strong_match' ? 'ready_for_recruiter' : 'review_required',
      debug: {
        matched_must_have: data.ai_result.matched_must_have,
        missing_must_have: data.ai_result.missing_must_have,
        matched_nice_to_have: data.ai_result.matched_nice_to_have,
      },
    },
  },
];
